+
+  private getCursorPagination(opts: CrudOptions): {
+    limit: number;
+    orderBy: Array<Record<string, 'asc' | 'desc'>>;
+    values?: Record<string, any>;
+  } | null {
+    const hasCursor = opts.cursor !== undefined;
+    if (hasCursor && !opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (hasCursor && opts.offset !== undefined) {
+      throw new BadRequestException('cursor and offset cannot be used together');
+    }
+    if (!opts.orderBy || !opts.limit) {
+      return null;
+    }
+
+    const orderBy = this.normalizeCursorOrderBy(opts.orderBy);
+    const values = hasCursor ? this.decodeCursor(opts.cursor, orderBy) : undefined;
+    return { limit: opts.limit, orderBy, values };
+  }
+
+  private normalizeCursorOrderBy(orderBy: any): Array<Record<string, 'asc' | 'desc'>> {
+    const parts = Array.isArray(orderBy) ? orderBy : [orderBy];
+    const normalized: Array<Record<string, 'asc' | 'desc'>> = [];
+    for (const part of parts) {
+      if (!part || typeof part !== 'object' || Array.isArray(part)) {
+        throw new BadRequestException('Invalid orderBy for cursor pagination');
+      }
+      for (const [field, direction] of Object.entries(part)) {
+        const normalizedDirection = String(direction).toLowerCase();
+        if (normalizedDirection !== 'asc' && normalizedDirection !== 'desc') {
+          throw new BadRequestException('Cursor pagination only supports asc and desc orderBy directions');
+        }
+        normalized.push({ [field]: normalizedDirection as 'asc' | 'desc' });
+      }
+    }
+    const idField = this.crudConfig.id_field;
+    if (!normalized.some((part) => Object.keys(part)[0] === idField)) {
+      normalized.push({ [idField]: 'asc' });
+    }
+    return normalized;
+  }
+
+  private decodeCursor(
+    cursor: string,
+    orderBy: Array<Record<string, 'asc' | 'desc'>>,
+  ): Record<string, any> {
+    let values: Record<string, any>;
+    try {
+      if (!/^[A-Za-z0-9+/]*={0,2}$/.test(cursor) || cursor.length % 4 !== 0) {
+        throw new Error();
+      }
+      const decoded = Buffer.from(cursor, 'base64').toString('utf8');
+      values = JSON.parse(decoded);
+      if (!values || typeof values !== 'object' || Array.isArray(values)) {
+        throw new Error();
+      }
+    } catch {
+      throw new BadRequestException('Invalid cursor');
+    }
+
+    const expectedSort = this.getCursorSort(orderBy);
+    if (values.__sort !== expectedSort) {
+      throw new BadRequestException('Cursor sort does not match orderBy');
+    }
+    const idField = this.crudConfig.id_field;
+    if (!(idField in values)) {
+      throw new BadRequestException(`Cursor is missing ${idField}`);
+    }
+    for (const part of orderBy) {
+      const field = Object.keys(part)[0];
+      if (!(field in values)) {
+        throw new BadRequestException(`Cursor is missing ${field}`);
+      }
+    }
+    return values;
+  }
+
+  private getCursorQuery(pagination: {
+    orderBy: Array<Record<string, 'asc' | 'desc'>>;
+    values?: Record<string, any>;
+  }) {
+    if (!pagination.values) {
+      return {};
+    }
+    const fields = pagination.orderBy.map((part) => Object.keys(part)[0]);
+    return {
+      $or: fields.map((field, index) => {
+        const equals = fields.slice(0, index).reduce(
+          (query, previousField) => ({
+            ...query,
+            [previousField]: pagination.values[previousField],
+          }),
+          {},
+        );
+        const direction = pagination.orderBy[index][field];
+        return {
+          ...equals,
+          [field]: { [direction === 'asc' ? '$gt' : '$lt']: pagination.values[field] },
+        };
+      }),
+    };
+  }
+
+  private encodeCursor(
+    entity: T,
+    orderBy: Array<Record<string, 'asc' | 'desc'>>,
+  ): string {
+    const cursor: Record<string, any> = { __sort: this.getCursorSort(orderBy) };
+    for (const part of orderBy) {
+      const field = Object.keys(part)[0];
+      cursor[field] = entity[field];
+    }
+    return Buffer.from(JSON.stringify(cursor)).toString('base64');
+  }
+
+  private getCursorSort(orderBy: Array<Record<string, 'asc' | 'desc'>>): string {
+    return orderBy
+      .map((part) => {
+        const field = Object.keys(part)[0];
+        return `${field}:${part[field]}`;
+      })
+      .join(',');
+  }
